INSERT INTO `jta_services` (`id`, `pharma_id`, `title`, `icon_class`, `img_cover`, `description`, `is_featured`, `is_deleted`, `created_at`, `updated_at`) VALUES
(1, 1, 'Preparazioni Galeniche Personalizzate', 'fas fa-flask', NULL, 'Realizzazione in laboratorio di farmaci su misura, secondo prescrizione medica, con consulenza diretta.', 1, 0, '2025-07-15 00:00:57', '2025-07-15 00:00:57'),
(2, 1, 'Misurazione della Glicemia', 'fas fa-syringe', NULL, 'Controllo rapido e professionale dei livelli di zucchero nel sangue in farmacia.', 0, 0, '2025-07-15 00:00:57', '2025-07-15 00:00:57'),
(3, 1, 'Misurazione Colesterolo e Trigliceridi', 'fas fa-tint', NULL, 'Check dei valori ematici con risultati disponibili in pochi minuti.', 0, 1, '2025-07-15 00:00:57', '2025-07-15 00:00:57'),
(4, 1, 'Misurazione della Pressione', 'fas fa-heartbeat', NULL, 'Realizzazione in laboratorio di farmaci su misura, secondo prescrizione medica, con consulenza diretta.Controllo costante e gratuito della pressione arteriosa.', 0, 0, '2025-07-15 00:00:57', '2025-07-15 00:00:57'),
(5, 1, 'Test per Intolleranze Alimentari', 'fas fa-dna', NULL, 'Analisi rapide per identificare eventuali intolleranze e migliorare il benessere quotidiano.', 0, 1, '2025-07-15 00:00:57', '2025-07-15 00:00:57'),
(6, 1, 'Consulenza su Integratori e Fitoterapia', 'fas fa-pills', NULL, 'Supporto personalizzato nella scelta di rimedi naturali e integratori adatti alle proprie esigenze.', 0, 0, '2025-07-15 00:00:57', '2025-07-15 00:00:57'),
(7, 1, 'Elettrocardiogramma (ECG)', 'fas fa-heartbeat', '{\"alt\": \"Copertina servizio: Elettrocardiogramma\", \"src\": \"/uploads/images/elettrocardiogramma-900x500-per-web-900x500.jpg\", \"mime\": \"image/jpeg\", \"width\": 1024, \"height\": 576, \"is_default\": true}', 'Un esame rapido e non invasivo che registra l’attività elettrica del cuore, fondamentale per individuare aritmie o altre anomalie cardiache.\r\n📄 Referto da cardiologo entro 24h.', 1, 0, '2025-08-27 10:00:00', '2025-08-27 10:00:00'),
(8, 1, 'Holter Pressorio (24h)', 'fas fa-circle-notch', NULL, 'Un dispositivo portatile con bracciale misura la pressione arteriosa durante tutta la giornata, consentendo di rilevare ipertensione o variazioni significative.\r\n📄 Referto entro 24h.', 0, 0, '2025-08-27 10:00:00', '2025-08-27 10:00:00'),
(9, 1, 'Holter Cardiaco (24-48h)', 'fas fa-heart-circle-exclamation', NULL, 'Un piccolo registratore monitora il cuore in continuo per 24-48 ore, permettendo di individuare aritmie intermittenti o disturbi non rilevabili con un ECG standard.\r\n📄 Referto entro 24-48h.', 0, 0, '2025-08-27 10:00:00', '2025-08-27 10:00:00'),
(10, 1, 'Consulenza Nutrizionista', 'fa-solid fa-apple-whole', NULL, 'Elaborazione di piani alimentari personalizzati e educazione nutrizionale per migliorare il benessere fisico.', 0, 0, '2025-08-27 13:00:00', '2025-08-27 13:00:00'),
(11, 1, 'Consulenza Posturologo', 'fa-solid fa-person-walking', NULL, 'Valutazione e correzione delle abitudini posturali per prevenire dolori e migliorare l\'allineamento corporeo.', 0, 0, '2025-08-27 13:00:00', '2025-08-27 13:00:00'),
(12, 1, 'Consulenza Tecnico Audiometrico', 'fa-solid fa-ear-deaf', NULL, 'Valutazione approfondita dell\'udito e scelta di soluzioni acustiche adeguate per migliorare la qualità dell\'ascolto.', 0, 0, '2025-08-27 13:00:00', '2025-08-27 13:00:00'),
(13, 1, 'Consulenza Tricologo', 'fa-solid fa-user-doctor', NULL, 'Analisi della salute dei capelli e del cuoio capelluto, con suggerimenti specifici per trattamenti mirati.', 0, 0, '2025-08-27 13:00:00', '2025-08-27 13:00:00'),
(14, 1, 'Ricognizione Terapeutica', 'fas fa-pills', NULL, 'Valutazione e riordino della terapia farmacologica in atto per prevenire interazioni dannose o controindicazioni.', 1, 0, '2025-08-28 12:00:00', '2025-08-28 12:00:00'),
(15, 1, 'Pelle d\'inverno', NULL, NULL, 'Consulenza per scoprire la routine ideale per il tuo tipo di pelle.', 1, 0, NULL, NULL),
(20, 2, 'Telemedicina', 'fas fa-heartbeat', NULL, 'ECG\nTeledermatologia\nHolter Pressorio\nHolter Cardiaco\nSpirometria\nScreening Venoso\nPolisonno\nHIGO', 0, 0, '2025-12-19 11:43:45', NULL),
(21, 2, 'Prelievi Capillari e Analisi', 'fas fa-vials', NULL, 'GLICEMIA\r\nINR\r\nPACCHETTO PROFILO LIPIDICO\r\nPACCHETTO CREATININA\r\nFUNZIONALITÀ RENALE\r\nPACCHETTO TRANSAMINASI + FUNZIONALITÀ FEGATO\r\nKIT PRELIEVO COMPLETO\r\nCELIACHIA\r\nTEST ALLERGIE\r\nINTOLLERANZE ALIMENTARI\r\nTAMPONE PER STREPTOCOCCO\r\nANALISI URINE', 0, 0, '2025-12-19 11:43:45', NULL),
(22, 2, 'Professionisti', 'fas fa-user-md', NULL, 'INFERMIERE\r\nNUTRIZIONISTA\r\nFISIOTERAPISTA\r\nLOGOPEDISTA\r\nOSTETRICIA\r\nOTTICO', 0, 0, '2025-12-19 11:43:45', NULL),
(23, 2, 'Servizi a domicilio', 'fas fa-home', NULL, 'TELEMEDICINA A DOMICILIO\r\nSERVIZI INFERMIERISTICI A DOMICILIO\r\nMANICURE E PEDICURE A DOMICILIO\r\nFISIOTERAPIA A DOMICILIO\r\nCONSEGNA A DOMICILIO', 0, 0, '2025-12-19 11:43:45', NULL);
